void main() {
  int apples = 25;
  int people = 7;

  int perPerson = apples ~/ people;
  int remaining = apples % people;

  print('$apples apples shared among $people people');
  print('Each gets $perPerson apples');
  print('$remaining apples remaining');

  double price = 19.99;
  double tax = price * 0.08;
  double total = price + tax;

  print('Price: \$${price.toStringAsFixed(2)}');
  print('Tax: \$${tax.toStringAsFixed(2)}');
  print('Total: \$${total.toStringAsFixed(2)}');
}
